mapper.select:
SELECT n_no, n_title, n_nb, n_date
FROM notice
WHERE n_no = #{n_no}

mapper.insert:
INSERT INTO notice (
    n_no, n_title, n_nb, n_date
) VALUES (
    seq_notice.NEXTVAL,
    #{n_title}, #{n_nb}, SYSDATE
)

mapper.update:
UPDATE notice
SET
  n_title = #{n_title, jdbcType=VARCHAR},
  n_nb    = #{n_nb, jdbcType=VARCHAR}
WHERE n_no = #{n_no, jdbcType=NUMERIC}
